---
-- Foothold localization table and helpers.
--
-- Load this file before setup files and before zoneCommanderv2.lua.
--
-- Usage:
--   FootholdLocalization:SetLocale("EN")
--   local text = FootholdLocalization:Get("COMMON_YES")
--   local text = FootholdLocalization:Format("SHOP_SPENT_CREDITS", player, amount, item)
--
-- Keep entries grouped by system so setup-file and zoneCommander work can be
-- converted in small, reviewable batches.

FootholdLocalization = FootholdLocalization or {}

local FL = FootholdLocalization

FL.DefaultLocale = FL.DefaultLocale or "EN"
FL.Locale = FL.Locale or FL.DefaultLocale
FL.Messages = FL.Messages or {}
FL.PlayerLocales = FL.PlayerLocales or {}
FL.GroupLocales = FL.GroupLocales or {}
FL.LocaleViews = FL.LocaleViews or {}

