local function normalizeLocale(locale)
	if locale == nil or locale == "" then return FL.DefaultLocale end
	local raw = tostring(locale)
	local upper = string.upper(raw)
	if upper == "ZH-TW" or upper == "ZH_TW" or upper == "ZHTW" or upper == "TW" then return "zh-TW" end
	if upper == "ZH-CN" or upper == "ZH_CN" or upper == "ZHCN" then return "zh-CN" end
	return upper
end

local function resolveLocale(locale)
	local localeKey = normalizeLocale(locale)
	if FL.Messages[localeKey] then
		return localeKey
	end
	return normalizeLocale(FL.DefaultLocale)
end

function FL:SetLocale(locale)
	self.Locale = resolveLocale(locale)
	return self.Locale
end

function FL:GetLocale()
	return resolveLocale(self.Locale)
end

function FL:Register(locale, entries)
	local localeKey = normalizeLocale(locale)
	self.Messages[localeKey] = self.Messages[localeKey] or {}
	for key, value in pairs(entries or {}) do
		self.Messages[localeKey][key] = value
	end
	return self
end

function FL:Get(key, locale)
	local keyName = tostring(key)
	local localeKey = resolveLocale(locale or self.Locale)
	local localeTable = self.Messages[localeKey]
	if localeTable and localeTable[keyName] ~= nil then
		return localeTable[keyName]
	end

	local defaultTable = self.Messages[normalizeLocale(self.DefaultLocale)]
	if defaultTable and defaultTable[keyName] ~= nil then
		return defaultTable[keyName]
	end

	return keyName
end

function FL:FormatForLocale(locale, key, ...)
	local text = self:Get(key, locale)
	if select("#", ...) == 0 then return text end
	return string.format(text, ...)
end

function FL:Format(key, ...)
	local text = self:Get(key)
	if select("#", ...) == 0 then return text end
	return string.format(text, ...)
end

function FL:Text(key, ...)
	return self:Format(key, ...)
end

function FL:DeferredGet(key)
	return function(T)
		return (T or self):Get(key)
	end
end

function FL:DeferredFormat(key, ...)
	local args = { ... }
	return function(T)
		return (T or self):Format(key, unpack(args))
	end
end

function FL:DynamicHeadingLabel(headingName, translator)
	local T = translator or self
	if headingName == "Orbit" then return T:Get("DYNAMIC_ORBIT") end
	local heading = tonumber(tostring(headingName):match("%d+"))
	if tostring(headingName):find("Reposition", 1, true) then
		return T:Format("DYNAMIC_REPOSITION_HEADING", heading)
	end
	return T:Format("DYNAMIC_HOT_HEADING", heading)
end

function FL:DynamicLegLabel(legName, translator)
	local T = translator or self
	if legName == "Orbit" then return T:Get("DYNAMIC_ORBIT") end
	return T:Format("DYNAMIC_NM_LEG", tonumber(tostring(legName):match("%d+")))
end

function FL:DynamicDistanceLabel(distanceName, translator)
	local T = translator or self
	return T:Format("DYNAMIC_NM_DISTANCE", tonumber(tostring(distanceName):match("%d+")))
end

function FL:SetPlayerLocale(playerName, locale)
	if type(playerName) ~= "string" or playerName == "" then
		return resolveLocale(locale or self.Locale)
	end
	local localeKey = resolveLocale(locale)
	self.PlayerLocales[playerName] = localeKey
	return localeKey
end

function FL:GetPlayerLocale(playerName)
	if type(playerName) == "string" and playerName ~= "" then
		local localeKey = self.PlayerLocales[playerName]
		if localeKey then
			return resolveLocale(localeKey)
		end
	end
	return self:GetLocale()
end

function FL:SetGroupLocale(groupID, locale)
	if groupID == nil then
		return resolveLocale(locale or self.Locale)
	end
	local localeKey = resolveLocale(locale)
	self.GroupLocales[tostring(groupID)] = localeKey
	return localeKey
end

function FL:BindGroupLocale(groupID, playerName)
	return self:SetGroupLocale(groupID, self:GetPlayerLocale(playerName))
end

function FL:ClearGroupLocale(groupID)
	if groupID ~= nil then
		self.GroupLocales[tostring(groupID)] = nil
	end
end

function FL:GetGroupLocale(groupID)
	if groupID ~= nil then
		local localeKey = self.GroupLocales[tostring(groupID)]
		if localeKey then
			return resolveLocale(localeKey)
		end
	end
	return self:GetLocale()
end

function FL:GetMooseGroupID(group)
	if not group then return nil end
	if group.GetID then return group:GetID() end
	if group.getID then return group:getID() end
	local dcsObject = group.GetDCSObject and group:GetDCSObject() or nil
	if dcsObject and dcsObject.getID then return dcsObject:getID() end
	return nil
end

function FL:GetMooseGroupLocale(group)
	return self:GetGroupLocale(self:GetMooseGroupID(group))
end

function FL:GetForGroup(groupID, key)
	return self:Get(key, self:GetGroupLocale(groupID))
end

function FL:FormatForGroup(groupID, key, ...)
	return self:FormatForLocale(self:GetGroupLocale(groupID), key, ...)
end

function FL:ForLocale(locale)
	local localeKey = resolveLocale(locale)
	local view = self.LocaleViews[localeKey]
	if view then return view end
	local owner = self
	view = {
		Locale = localeKey,
		Get = function(_, key) return owner:Get(key, localeKey) end,
		Format = function(_, key, ...) return owner:FormatForLocale(localeKey, key, ...) end,
		Text = function(_, key, ...) return owner:FormatForLocale(localeKey, key, ...) end,
	}
	self.LocaleViews[localeKey] = view
	return view
end

function FL:ForGroup(groupID)
	return self:ForLocale(self:GetGroupLocale(groupID))
end

function FL:ForMooseGroup(group)
	return self:ForLocale(self:GetMooseGroupLocale(group))
end

function FL:ExportPlayerLocales()
	local list = {}
	for playerName, locale in pairs(self.PlayerLocales or {}) do
		if type(playerName) == "string" and playerName ~= "" then
			list[#list + 1] = { name = playerName, locale = resolveLocale(locale) }
		end
	end
	table.sort(list, function(a, b) return a.name < b.name end)
	return list
end

function FL:ImportPlayerLocales(entries)
	self.PlayerLocales = {}
	if type(entries) ~= "table" then return end
	for playerName, locale in pairs(entries) do
		if type(playerName) == "string" and type(locale) == "string" then
			self:SetPlayerLocale(playerName, locale)
		end
	end
	for _, entry in ipairs(entries) do
		if type(entry) == "table" and entry.name and entry.locale then
			self:SetPlayerLocale(entry.name, entry.locale)
		end
	end
end

if FootholdLocale ~= nil then
	FL:SetLocale(FootholdLocale)
end

